import type { Metadata } from "next";
import { headers } from "next/headers";
import { getSiteContent } from "@/lib/content-store";
import "./globals.css";

export async function generateMetadata(): Promise<Metadata> {
  const { settings } = await getSiteContent();
  const requestHeaders = await headers();
  const host = requestHeaders.get("x-forwarded-host") ?? requestHeaders.get("host") ?? "ulucanhafriyat.com";
  const protocol = requestHeaders.get("x-forwarded-proto") ?? (host.includes("localhost") ? "http" : "https");
  const base = new URL(`${protocol}://${host}`);
  return {
    metadataBase: base,
    title: { default: settings.seoTitle, template: "%s | Ulucan Hafriyat" },
    description: settings.seoDescription,
    keywords: ["hafriyat", "inşaat", "taahhüt", "kazı", "dolgu", "altyapı", "iş makinesi", "İstanbul hafriyat"],
    alternates: { canonical: base },
    verification: settings.googleSiteVerification ? { google: settings.googleSiteVerification } : undefined,
    openGraph: { title: "Ulucan Hafriyat", description: "Zeminden geleceğe güvenle.", type: "website", images: [{ url: new URL("/og.png", base).toString(), width: 1664, height: 941, alt: "Ulucan Hafriyat" }] },
    twitter: { card: "summary_large_image", title: "Ulucan Hafriyat", description: "Zeminden geleceğe güvenle.", images: [new URL("/og.png", base).toString()] },
    icons: { icon: settings.emblemLogoUrl, shortcut: settings.emblemLogoUrl, apple: settings.emblemLogoUrl },
  };
}

export default function RootLayout({ children }: Readonly<{ children: React.ReactNode }>) {
  const structuredData = { "@context": "https://schema.org", "@type": ["Organization", "LocalBusiness"], name: "Ulucan Hafriyat", url: "https://ulucanhafriyat.com", telephone: "+90 212 597 99 13", email: "info@ulucanhafriyat.com", address: { "@type": "PostalAddress", streetAddress: "Boğazköy İstiklal Mahallesi Türksoy Caddesi No:12", addressLocality: "Arnavutköy", addressRegion: "İstanbul", addressCountry: "TR" }, areaServed: "İstanbul", knowsAbout: ["Hafriyat", "Kazı ve dolgu", "Altyapı", "İnşaat", "Taahhüt"] };
  return <html lang="tr" suppressHydrationWarning><head><script dangerouslySetInnerHTML={{ __html: `(function(){try{var saved=localStorage.getItem('ulucan-theme');var theme=saved||(matchMedia('(prefers-color-scheme: dark)').matches?'dark':'light');document.documentElement.dataset.theme=theme}catch(e){}})()` }} /><script type="application/ld+json" dangerouslySetInnerHTML={{ __html: JSON.stringify(structuredData) }} /></head><body>{children}</body></html>;
}
